import{_ as i,a,b as n}from"./chunks/管理端登录界面.yuERlcJ6.js";import{_ as t,o,c as l,a2 as s}from"./chunks/framework.DnrXFDHb.js";const f=JSON.parse('{"title":"Authentication နှင့် Login Device Management","description":"","frontmatter":{},"headers":[],"relativePath":"my/Safety/authentication-and-login-devices.md","filePath":"my/Safety/authentication-and-login-devices.md","lastUpdated":1781962217000}'),d={name:"my/Safety/authentication-and-login-devices.md"};function r(c,e,u,p,m,h){return o(),l("div",null,[...e[0]||(e[0]=[s('<h1 id="authentication-နှင့်-login-device-management" tabindex="-1">Authentication နှင့် Login Device Management <a class="header-anchor" href="#authentication-နှင့်-login-device-management" aria-label="Permalink to &quot;Authentication နှင့် Login Device Management&quot;">​</a></h1><p><code>Authentication Management</code> နှင့် <code>Login Device Management</code> က ImgBed admin panel, public upload entry, WebDAV access တို့ကိုကာကွယ်ပေးပါတယ်။</p><p>ဒီစာမျက်နှာမှာ access credentials သတ်မှတ်နိုင်ပြီး signed-in devices စစ်နိုင်သလို လိုအပ်သည့်အခါ sessions အဟောင်းတွေကို revoke လုပ်နိုင်ပါတယ်။</p><h2 id="ဘယ်နေရာမှာ-configure-လုပ်မလဲ" tabindex="-1">ဘယ်နေရာမှာ Configure လုပ်မလဲ <a class="header-anchor" href="#ဘယ်နေရာမှာ-configure-လုပ်မလဲ" aria-label="Permalink to &quot;ဘယ်နေရာမှာ Configure လုပ်မလဲ&quot;">​</a></h2><p>admin panel ကိုဖွင့်ပြီး သွားပါ:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Security Settings</span></span></code></pre></div><p>page ထဲမှာ main areas နှစ်ခုရှိပါတယ်:</p><ul><li>Authentication Management</li><li>Login Device Management</li></ul><p><img src="'+i+'" alt="Authentication management" loading="lazy"></p><h2 id="authentication-management-က-ဘာလုပ်လဲ" tabindex="-1">Authentication Management က ဘာလုပ်လဲ <a class="header-anchor" href="#authentication-management-က-ဘာလုပ်လဲ" aria-label="Permalink to &quot;Authentication Management က ဘာလုပ်လဲ&quot;">​</a></h2><p>Authentication Management က access credentials တွေကိုသိမ်းပါတယ်။</p><p>အမျိုးအစားနှစ်မျိုးရှိပါတယ်:</p><ul><li>User-side authentication</li><li>Admin-side authentication</li></ul><h2 id="user-side-authentication" tabindex="-1">User-Side Authentication <a class="header-anchor" href="#user-side-authentication" aria-label="Permalink to &quot;User-Side Authentication&quot;">​</a></h2><p>User-side authentication ဆိုတာ upload password ဖြစ်ပါတယ်။</p><p>upload password သတ်မှတ်ပြီးရင် regular visitors တွေက upload page မသုံးခင် password ထည့်ရပါမယ်။ public upload page ကိုလူတိုင်းအတွက်မဖွင့်ချင်တဲ့အခါအသုံးဝင်ပါတယ်။</p><p><img src="'+a+'" alt="User login page" loading="lazy"></p><h3 id="upload-password-သတ်မှတ်ခြင်း" tabindex="-1">Upload Password သတ်မှတ်ခြင်း <a class="header-anchor" href="#upload-password-သတ်မှတ်ခြင်း" aria-label="Permalink to &quot;Upload Password သတ်မှတ်ခြင်း&quot;">​</a></h3><p>upload password configured ဖြစ်နေတဲ့အခါ:</p><ul><li>visitors တွေက upload page မသုံးခင် password ထည့်ရပါမယ်။</li><li>password ကိုလက်ခံပြီးမှ upload လုပ်နိုင်ပါမယ်။</li><li>user-side device sessions enabled ဖြစ်လျှင် ImgBed က user-side device ကို record လုပ်ပါမယ်။</li></ul><p>upload password ပြောင်းလဲခြင်းက user-side sessions အဟောင်းတွေကို invalid ဖြစ်စေပါတယ်။ visitors တွေက password အသစ်ကိုပြန်ထည့်ရပါမယ်။</p><h2 id="admin-side-authentication" tabindex="-1">Admin-Side Authentication <a class="header-anchor" href="#admin-side-authentication" aria-label="Permalink to &quot;Admin-Side Authentication&quot;">​</a></h2><p>Admin-side authentication က admin username နဲ့ password ကိုသုံးပါတယ်။</p><p>ဒါက admin panel ကိုကာကွယ်ပေးပါတယ်။ production use အတွက် အမြဲ configure လုပ်ထားသင့်ပါတယ်။</p><p><img src="'+n+'" alt="Admin login page" loading="lazy"></p><h3 id="admin-credentials-သတ်မှတ်ခြင်း" tabindex="-1">Admin Credentials သတ်မှတ်ခြင်း <a class="header-anchor" href="#admin-credentials-သတ်မှတ်ခြင်း" aria-label="Permalink to &quot;Admin Credentials သတ်မှတ်ခြင်း&quot;">​</a></h3><p>admin username နဲ့ password configured ဖြစ်နေတဲ့အခါ:</p><ul><li>admin panel ဖွင့်ဖို့ login လုပ်ရပါမယ်။</li><li>login အောင်မြင်ရင် admin device record တစ်ခုဖန်တီးပါမယ်။</li><li>Login Device Management မှာ devices တွေကို review, clean up, force offline လုပ်နိုင်ပါတယ်။</li></ul><p>admin username သို့မဟုတ် password ပြောင်းလဲခြင်းက admin sessions အဟောင်းတွေကို invalid ဖြစ်စေပါတယ်။ ပြန် sign in ဝင်ရပါမယ်။</p><h2 id="login-device-management-က-ဘာလုပ်လဲ" tabindex="-1">Login Device Management က ဘာလုပ်လဲ <a class="header-anchor" href="#login-device-management-က-ဘာလုပ်လဲ" aria-label="Permalink to &quot;Login Device Management က ဘာလုပ်လဲ&quot;">​</a></h2><p>Login Device Management က sign in ဝင်ထားတဲ့ devices တွေကိုပြပါတယ်။</p><p>ဒီအချက်တွေစစ်ရာမှာကူညီပါတယ်:</p><ul><li>ဘယ် devices တွေက admin panel ကို access လုပ်ခဲ့လဲ။</li><li>ဘယ် devices တွေက user-side upload page ကို access လုပ်ခဲ့လဲ။</li><li>ဘယ် WebDAV clients တွေ connect လုပ်ခဲ့လဲ။</li><li>device session က valid ဖြစ်နေသေးလား။</li><li>devices အဟောင်းတွေကို force offline လုပ်သင့်လား။</li></ul><p>page မှာ tabs သုံးခုရှိပါတယ်:</p><ul><li>Admin</li><li>User</li><li>WebDAV</li></ul><h2 id="global-cookie-security" tabindex="-1">Global Cookie Security <a class="header-anchor" href="#global-cookie-security" aria-label="Permalink to &quot;Global Cookie Security&quot;">​</a></h2><p>Login Device Management အပေါ်ပိုင်းမှာ global cookie behavior ကို configure လုပ်နိုင်ပါတယ်။</p><h3 id="user-cookie-lifetime" tabindex="-1">User Cookie Lifetime <a class="header-anchor" href="#user-cookie-lifetime" aria-label="Permalink to &quot;User Cookie Lifetime&quot;">​</a></h3><p>user-side login က ဘယ်နှစ်ရက် active ဖြစ်နိုင်လဲ ထိန်းချုပ်ပါတယ်။</p><p>ဥပမာ 14 days ထားလျှင် visitors တွေက များသောအားဖြင့် 14 ရက်အတွင်း upload password ပြန်ထည့်စရာမလိုပါ။</p><h3 id="admin-cookie-lifetime" tabindex="-1">Admin Cookie Lifetime <a class="header-anchor" href="#admin-cookie-lifetime" aria-label="Permalink to &quot;Admin Cookie Lifetime&quot;">​</a></h3><p>admin login က ဘယ်နှစ်ရက် active ဖြစ်နိုင်လဲ ထိန်းချုပ်ပါတယ်။</p><p>ဥပမာ 14 days ထားလျှင် administrators တွေက များသောအားဖြင့် 14 ရက်အတွင်း ပြန် sign in ဝင်စရာမလိုပါ။</p><h3 id="secure-mode" tabindex="-1">Secure Mode <a class="header-anchor" href="#secure-mode" aria-label="Permalink to &quot;Secure Mode&quot;">​</a></h3><p>Secure mode enabled ဖြစ်လျှင် browsers တွေက login cookies ကို HTTPS ပေါ်မှသာပို့ပါမယ်။</p><p>production HTTPS sites တွေအတွက် enable လုပ်ပါ။ local HTTP testing အတွက် enable မလုပ်ပါနှင့်၊ မဟုတ်ရင် &quot;login succeeded, but refresh logs me out&quot; လို behavior မြင်နိုင်ပါတယ်။</p><h2 id="admin-login-devices" tabindex="-1">Admin Login Devices <a class="header-anchor" href="#admin-login-devices" aria-label="Permalink to &quot;Admin Login Devices&quot;">​</a></h2><p>Admin tab က admin panel ထဲ sign in ဝင်ခဲ့တဲ့ devices တွေကိုပြပါတယ်။</p><p>device records တွေက admin credentials configured ဖြစ်ပြီး admin panel ကို login မှတစ်ဆင့် access လုပ်ပြီးမှပေါ်လာပါမယ်။</p><p>device card တစ်ခုစီမှာ ပြနိုင်တာတွေ:</p><ul><li>device နဲ့ browser information</li><li>first login IP</li><li>last active IP</li><li>login time</li><li>last active time</li><li>expiration time</li><li>current status</li></ul><p>မသိတဲ့ device တွေ့ရင် <code>Force Offline</code> နဲ့ invalidate လုပ်ပါ။</p><h2 id="clean-up-old-devices" tabindex="-1">Clean Up Old Devices <a class="header-anchor" href="#clean-up-old-devices" aria-label="Permalink to &quot;Clean Up Old Devices&quot;">​</a></h2><p><code>Clean Up Old Devices</code> က current tab ထဲက login records အဟောင်းတွေကို bulk remove လုပ်ပါတယ်။</p><p>အခြား devices တွေမှာ sessions အဟောင်းတွေ active ဖြစ်နေနိုင်တယ်လို့ သံသယရှိလျှင်သုံးပါ။</p><h2 id="force-offline" tabindex="-1">Force Offline <a class="header-anchor" href="#force-offline" aria-label="Permalink to &quot;Force Offline&quot;">​</a></h2><p><code>Force Offline</code> က device session တစ်ခုကို invalidate လုပ်ပါတယ်။</p><p>device တစ်ခု force offline ဖြစ်ပြီးနောက်:</p><ul><li>Admin devices တွေက ပြန် sign in ဝင်ရပါမယ်။</li><li>User-side devices တွေက upload password ပြန်ထည့်ရပါမယ်။</li><li>WebDAV clients တွေက ပြန် authenticate လုပ်ရပါမယ်။</li></ul><p>Expired သို့မဟုတ် invalid devices တွေကိုလည်း remove လုပ်နိုင်ပါတယ်။</p><h2 id="sign-out-current-device" tabindex="-1">Sign Out Current Device <a class="header-anchor" href="#sign-out-current-device" aria-label="Permalink to &quot;Sign Out Current Device&quot;">​</a></h2><p>current device card ကို <code>Current Device</code> လို့ mark လုပ်ထားပါတယ်။</p><p>current device မှ sign out လုပ်ပြီးနောက်:</p><ul><li>current admin session sign out ဖြစ်ပါမယ်။</li><li>current user-side session sign out ဖြစ်ပါမယ်။</li></ul><p>အဲဒီ area ကိုဆက်သုံးမယ်ဆိုရင် ပြန် sign in ဝင်ရပါမယ်။</p>',65)])])}const b=t(d,[["render",r]]);export{f as __pageData,b as default};
